// EDTMRS - Device Monitor Page
import React, { useState, useEffect, useCallback } from 'react';
import { devicesAPI, actionsAPI } from '../utils/api';
import RiskBadge from '../components/RiskBadge';

const RISK_FILTERS = ['all', 'critical', 'high', 'medium', 'safe', 'unknown'];

function DeviceActionModal({ device, onClose, onDone }) {
  const [reason, setReason] = useState('');
  const [loading, setLoading] = useState(false);

  const doBlock = async () => {
    setLoading(true);
    try {
      await actionsAPI.blockDevice({
        vendor_id: device.vendor_id,
        product_id: device.product_id,
        serial_number: device.serial_number,
        device_name: device.device_name,
        reason: reason || 'Blocked by administrator',
      });
      onDone('blocked');
    } finally { setLoading(false); }
  };

  const doWhitelist = async () => {
    setLoading(true);
    try {
      await actionsAPI.whitelistDevice({
        vendor_id: device.vendor_id,
        product_id: device.product_id,
        serial_number: device.serial_number,
        device_name: device.device_name,
        notes: reason,
      });
      onDone('whitelisted');
    } finally { setLoading(false); }
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-2xl p-6 w-full max-w-md shadow-2xl">
        <div className="flex items-center justify-between mb-5">
          <h3 className="text-white font-bold">Device Action</h3>
          <button onClick={onClose} className="text-gray-500 hover:text-white text-xl leading-none">✕</button>
        </div>
        <div className="bg-[#141d35] rounded-xl p-4 mb-5 space-y-1.5 text-sm">
          <div className="flex justify-between"><span className="text-gray-500">Name</span><span className="text-white font-medium truncate max-w-[60%]">{device.device_name}</span></div>
          <div className="flex justify-between"><span className="text-gray-500">VID</span><span className="text-gray-300 font-mono">{device.vendor_id}</span></div>
          <div className="flex justify-between"><span className="text-gray-500">PID</span><span className="text-gray-300 font-mono">{device.product_id}</span></div>
          <div className="flex justify-between"><span className="text-gray-500">Serial</span><span className="text-gray-300 font-mono text-xs truncate max-w-[60%]">{device.serial_number}</span></div>
          <div className="flex justify-between"><span className="text-gray-500">Host</span><span className="text-gray-300">{device.hostname}</span></div>
          <div className="flex justify-between items-center"><span className="text-gray-500">Risk</span><RiskBadge level={device.risk_level} /></div>
        </div>
        <div className="mb-5">
          <label className="block text-xs text-gray-500 uppercase tracking-wider mb-2">Notes / Reason (optional)</label>
          <input
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            placeholder="Enter reason..."
            className="w-full bg-[#141d35] border border-[#1e2d4d] text-white placeholder-gray-600 rounded-lg px-3 py-2.5 text-sm focus:outline-none focus:border-blue-500"
          />
        </div>
        <div className="flex gap-3">
          <button onClick={doWhitelist} disabled={loading}
            className="flex-1 bg-emerald-600/20 hover:bg-emerald-600/30 border border-emerald-500/40 text-emerald-400 font-semibold rounded-lg py-2.5 text-sm transition-all">
            ✓ Whitelist
          </button>
          <button onClick={doBlock} disabled={loading}
            className="flex-1 bg-red-600/20 hover:bg-red-600/30 border border-red-500/40 text-red-400 font-semibold rounded-lg py-2.5 text-sm transition-all">
            ⊘ Block
          </button>
        </div>
      </div>
    </div>
  );
}

export default function DevicesPage({ liveEvents }) {
  const [devices, setDevices]       = useState([]);
  const [total, setTotal]           = useState(0);
  const [loading, setLoading]       = useState(true);
  const [search, setSearch]         = useState('');
  const [riskFilter, setRiskFilter] = useState('all');
  const [selected, setSelected]     = useState(null);
  const [toast, setToast]           = useState('');

  const fetchDevices = useCallback(async () => {
    try {
      const res = await devicesAPI.list({
        search: search || undefined,
        risk_level: riskFilter === 'all' ? undefined : riskFilter,
        limit: 100,
      });
      setDevices(res.data.devices);
      setTotal(res.data.total);
    } finally { setLoading(false); }
  }, [search, riskFilter]);

  useEffect(() => { fetchDevices(); }, [fetchDevices]);
  useEffect(() => { if (liveEvents?.length) fetchDevices(); }, [liveEvents, fetchDevices]);

  const handleDone = (action) => {
    setSelected(null);
    setToast(`Device ${action} successfully`);
    setTimeout(() => setToast(''), 3000);
    fetchDevices();
  };

  return (
    <div className="space-y-5">
      {toast && (
        <div className="fixed top-5 right-5 z-50 px-4 py-3 bg-emerald-600/20 border border-emerald-500/40 text-emerald-400 rounded-xl text-sm shadow-xl">
          ✓ {toast}
        </div>
      )}
      {selected && <DeviceActionModal device={selected} onClose={() => setSelected(null)} onDone={handleDone} />}

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-white">Device Monitor</h1>
          <p className="text-gray-500 text-sm mt-0.5">{total} device events recorded</p>
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-3">
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search by name, host, serial, VID..."
          className="bg-[#0f1629] border border-[#1e2d4d] text-white placeholder-gray-600 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:border-blue-500 w-72"
        />
        <div className="flex gap-1.5">
          {RISK_FILTERS.map((f) => (
            <button key={f} onClick={() => setRiskFilter(f)}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium capitalize transition-all ${
                riskFilter === f
                  ? 'bg-blue-600 text-white'
                  : 'bg-[#0f1629] border border-[#1e2d4d] text-gray-400 hover:text-white'
              }`}>
              {f}
            </button>
          ))}
        </div>
      </div>

      {/* Table */}
      <div className="bg-[#0f1629] border border-[#1e2d4d] rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-[#1e2d4d] text-gray-500 text-xs uppercase tracking-wider">
                <th className="px-4 py-3 text-left">Device Name</th>
                <th className="px-4 py-3 text-left">VID / PID</th>
                <th className="px-4 py-3 text-left">Serial</th>
                <th className="px-4 py-3 text-left">Drive</th>
                <th className="px-4 py-3 text-left">Endpoint</th>
                <th className="px-4 py-3 text-left">User</th>
                <th className="px-4 py-3 text-left">Risk</th>
                <th className="px-4 py-3 text-left">Timestamp</th>
                <th className="px-4 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={9} className="text-center py-16 text-gray-600">
                  <div className="flex justify-center"><div className="w-6 h-6 border-2 border-blue-500/30 border-t-blue-400 rounded-full animate-spin" /></div>
                </td></tr>
              ) : !devices.length ? (
                <tr><td colSpan={9} className="text-center py-16 text-gray-600">
                  <div className="text-2xl mb-2">⊡</div>
                  <div>No devices found</div>
                </td></tr>
              ) : devices.map((d) => (
                <tr key={d.id} className="border-b border-[#1a2035] hover:bg-white/2 transition-colors">
                  <td className="px-4 py-3">
                    <div className="text-white font-medium truncate max-w-[180px]">{d.device_name}</div>
                    <div className="text-gray-600 text-xs">{d.device_type}</div>
                  </td>
                  <td className="px-4 py-3 font-mono text-gray-300 text-xs">
                    <div>{d.vendor_id}</div>
                    <div className="text-gray-600">{d.product_id}</div>
                  </td>
                  <td className="px-4 py-3 font-mono text-gray-400 text-xs max-w-[120px] truncate">{d.serial_number}</td>
                  <td className="px-4 py-3 font-mono text-gray-300 text-xs">{d.drive_letter || '—'}</td>
                  <td className="px-4 py-3 text-gray-300 text-xs">{d.hostname}</td>
                  <td className="px-4 py-3 text-gray-400 text-xs">{d.username}</td>
                  <td className="px-4 py-3"><RiskBadge level={d.risk_level} pulse /></td>
                  <td className="px-4 py-3 text-gray-500 text-xs whitespace-nowrap">
                    {d.timestamp ? new Date(d.timestamp).toLocaleString() : '—'}
                  </td>
                  <td className="px-4 py-3">
                    <button onClick={() => setSelected(d)}
                      className="px-2.5 py-1 bg-[#141d35] hover:bg-blue-600/20 border border-[#1e2d4d] hover:border-blue-500/40 text-gray-400 hover:text-blue-400 rounded-lg text-xs transition-all">
                      Actions
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
